  '709c9a59-2518-4f95-8f11-0a20680af7ca',
  '00000000-0000-0000-0000-000000000001',
  $escape$Turbopack Config — Zero-Config Defaults vs. Explicit turbo.config.ts$escape$,
  $escape$Turbopack ships zero-config inside Next.js: run `next dev --turbopack` and it resolves aliases, handles CSS Modules, and tree-shakes without a single config line. That default pipeline covers ~95% of apps.

When you need to step outside that default, you reach for `turbo.config.ts` (or the `experimental.turbo` key inside `next.config.ts` for Next.js 14+). The two levers you'll actually touch are `resolveAlias` — a direct replacement for webpack's `resolve.alias` — and `rules`, which maps file extensions to custom loaders. Turbopack rules use the `loaders` array, each entry specifying a `loader` package and `options`, mirroring webpack loader syntax but evaluated by Turbopack's Rust core, not Node.

Critical distinction: Turbopack does **not** read `webpack.config.js`. Any custom loader you relied on must be re-declared under `rules`. Not all webpack loaders are compatible — Turbopack only supports a subset of the webpack loader API. Check the official compatibility list before migrating. For monorepos, `turbo.json` at the workspace root controls task pipelines (build, lint, test), which is a separate concern from the bundler config.$escape$,
  $escape$// next.config.ts (Next.js 14+ turbopack config)
import type { NextConfig } from 'next';

const config: NextConfig = {
  experimental: {
    turbo: {
      resolveAlias: {
        '@ui': './src/components/ui',
        '@lib': './src/lib',
      },
      rules: {
        '*.svg': {
          loaders: ['@svgr/webpack'],
          as: '*.js',
        },
      },
    },
  },
};

export default config;$escape$,
  $escape$typescript$escape$,
