INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'ccc9b14a-0f47-476c-8995-64b7729701da',
  '00000000-0000-0000-0000-000000000001',
  $escape$Turbopack Dev Server — HMR, Proxy Setup, and HTTPS in Dev$escape$,
  $escape$Turbopack's dev server ships with React Fast Refresh-backed HMR out of the box. Unlike webpack's full-module replacement, Turbopack tracks fine-grained module boundaries and only re-evaluates the exact changed module plus its direct dependents — keeping HMR updates sub-50ms even in large apps. No manual `hot.accept()` wiring needed for React components.

For proxying API requests, configure `rewrites` in `next.config.ts`. Turbopack respects Next.js rewrites natively — no separate `devServer.proxy` block like webpack requires. Add a `rewrites` async function and Turbopack picks it up without a server restart.

For HTTPS in dev, pass `--experimental-https` to `next dev --turbopack`. This auto-generates a self-signed cert via `mkcert` and serves over `https://localhost:3000`. Pair it with `NODE_EXTRA_CA_CERTS` if your fetch calls hit internal services that reject self-signed certs. Turbopack does not yet support custom cert paths via config — the `--experimental-https` flag is the only supported path as of Next.js 15.$escape$,
  $escape$// next.config.ts
import type { NextConfig } from 'next';

const config: NextConfig = {
  async rewrites() {
    return [
      {
        source: '/api/:path*',
        destination: 'http://localhost:4000/:path*',
      },
    ];
  },
};

export default config;

// package.json — dev script
// "dev": "next dev --turbopack --experimental-https"$escape$,
