INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '27d812f4-34ab-42ac-8c93-73937414f8c3',
  '00000000-0000-0000-0000-000000000001',
  $escape$Turbopack Code Splitting — Dynamic Imports, Manual Chunks, and Route-Based Boundaries$escape$,
  $escape$Turbopack performs automatic route-based splitting in Next.js 13+ app directory — each `page.tsx` becomes its own chunk boundary without configuration. But you control granularity further with dynamic imports via `next/dynamic`, which Turbopack traces statically at build time rather than deferring to runtime like webpack.

Unlike webpack's `optimization.splitChunks`, Turbopack has no manual chunk configuration API yet — chunk splitting is graph-driven, inferred from your import graph. This means co-located heavy dependencies (e.g. a charting lib used in one route) are automatically isolated if they aren't shared across entry points.

For explicit splitting, `next/dynamic` with `ssr: false` tells Turbopack to exclude the module from the server graph entirely, shrinking your server bundle. Pair it with `loading` for streaming UX. Turbopack also respects `React.lazy` + `Suspense` for client-only split points, but `next/dynamic` gives you the `ssr` escape hatch `React.lazy` doesn't.

Avoid barrel files (`index.ts` re-exporting everything) — Turbopack's tree-shaking operates per-module, and barrels collapse chunk boundaries by merging import graphs.$escape$,
  $escape$import dynamic from 'next/dynamic'

// Excluded from server bundle; own client chunk
const HeavyChart = dynamic(
  () => import('@/components/HeavyChart'),
  {
    ssr: false,
    loading: () => <p>Loading chart...</p>,
  }
)

// Route-based: app/dashboard/page.tsx is already a split point.
// Dynamic import adds a *nested* chunk within that route chunk.
export default function DashboardPage() {
  return <HeavyChart />
}$escape$,
  $escape$typescript$escape$,
