INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '7ba075a3-b88a-4c5b-8fe4-2d3fb95cca17',
  '00000000-0000-0000-0000-000000000001',
  $escape$Turbopack Tree Shaking — Why sideEffects Is the Flag That Actually Matters$escape$,
  $escape$Turbopack performs tree shaking at the module graph level using its Rust-based static analyzer, not at emit time like webpack. When it encounters an ESM import, it traces export bindings through its internal EcmascriptChunkItem graph and prunes exports with no live references before evaluation.

The sideEffects field in package.json is the critical signal. If absent or true, Turbopack must retain every imported module file even if no exports are used — any file might mutate globals, patch prototypes, or register effects. Set "sideEffects": false to declare the entire package pure; use an array (["**/*.css", "src/polyfills.ts"]) to whitelist only files with real effects.

For monorepo internal packages, add "sideEffects": false to each package's package.json. Turbopack will then eliminate barrel-imported but unused modules entirely. Without it, a barrel like export * from './components' forces every component module into the bundle regardless of usage.

CSS imports are always side-effectful — list them explicitly or Turbopack may silently drop your styles.$escape$,
  $escape$// packages/ui/package.json — mark package as pure
// "sideEffects": ["**/*.css", "src/polyfills.ts"]

// packages/ui/src/index.ts — barrel file
export { Button } from './Button';
export { Modal } from './Modal';
export { Tooltip } from './Tooltip';

// app/page.tsx
// Turbopack statically analyzes this import:
// Button is bundled; Modal + Tooltip are fully pruned.
import { Button } from '@byteai/ui';$escape$,
  $escape$typescript$escape$,
