INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '8e3a5161-7a1c-4793-9010-b59a68b3b09e',
  '00000000-0000-0000-0000-000000000001',
  $escape$Turbopack Bundle Analysis — Visualizing Size, Finding Bloat, and Enforcing CI Budgets$escape$,
  $escape$Turbopack doesn't support `@next/bundle-analyzer` — that package requires webpack mode. To get a treemap visualization, drop the turbopack flag temporarily: `ANALYZE=true next build` (webpack) gives you the familiar interactive treemap via `@next/bundle-analyzer`. This is a deliberate workflow split: use webpack for periodic audit, Turbopack for fast daily iteration.

For continuous size enforcement in CI, Turbopack emits client chunks to `.next/static/chunks/` after every `next build --turbopack`. Script against that directory to catch regressions before merge. The `turbopack` config key in `next.config.ts` (promoted from `experimental.turbo` in Next.js 15) handles resolver aliases and custom loaders — budget enforcement is intentionally a CI-layer concern, not a bundler config concern.

To find bloat without a treemap, check `.next/build-manifest.json` for which pages pull in which chunks, then cross-reference chunk filenames with the emitted files. Large shared chunks under `chunks/` signal unintentional module coalescing across routes. Run the script below as a `check:size` step after `next build` in your GitHub Actions workflow.$escape$,
  $escape$// scripts/check-bundle-size.ts — runs after `next build --turbopack`
import { readdirSync, statSync } from 'fs'
import { join } from 'path'

const CHUNK_DIR = join(process.cwd(), '.next/static/chunks')
const MAX_CHUNK_KB = 250

const chunks = readdirSync(CHUNK_DIR).filter(f => f.endsWith('.js'))
const violations: string[] = []

for (const chunk of chunks) {
  const sizeKB = statSync(join(CHUNK_DIR, chunk)).size / 1024
  if (sizeKB > MAX_CHUNK_KB)
    violations.push(`  ${chunk}: ${sizeKB.toFixed(1)}KB > ${MAX_CHUNK_KB}KB`)
}

if (violations.length) {
  console.error('Bundle budget exceeded:\n' + violations.join('\n'))
  process.exit(1)
}
console.log(`✓ All ${chunks.length} chunks within ${MAX_CHUNK_KB}KB budget.`)$escape$,
  $escape$typescript$escape$,
