INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '7e4ad764-3561-4b9a-8309-295f4ec05659',
  '00000000-0000-0000-0000-000000000001',
  $escape$Turbopack Asset Handling — Images, Fonts, SVGs, and Content Hashing$escape$,
  $escape$Turbopack processes static assets through its native asset pipeline, distinct from webpack's `file-loader` or `url-loader` approach. Import an image directly and Turbopack resolves it to a content-hashed URL automatically — no loader config required.

For images, Turbopack inlines assets below 8KB as base64 data URIs by default and emits larger files with a `[contenthash]` fingerprint (e.g., `logo.a3f9c1d2.png`), enabling aggressive long-term caching without manual cache-busting.

SVGs imported as modules are treated as raw strings unless you configure a custom transform. In Next.js 15+ with Turbopack enabled, `@svgr/webpack` is replaced by the built-in `experimental.turbo.rules` — map `*.svg` to a custom Turbopack loader that returns a React component.

Fonts referenced via CSS `@font-face` or Next.js `next/font` are tracked as module graph edges. Turbopack hashes font files independently, so a font update busts only its own cache entry — not the entire CSS bundle. Unlike webpack, Turbopack never re-emits unchanged assets, making incremental builds with many static files significantly faster.$escape$,
  $escape$// next.config.ts — Turbopack SVG rule (Next.js 15+)
import type { NextConfig } from 'next';

const config: NextConfig = {
  experimental: {
    turbopack: {
      rules: {
        '*.svg': {
          loaders: ['@svgr/webpack'],
          as: '*.js',
        },
      },
    },
  },
};

export default config;$escape$,
  $escape$typescript$escape$,
