INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '9325ceb4-be70-4277-ae77-dd68462ea0c8',
  '00000000-0000-0000-0000-000000000001',
  $escape$Turbopack Environment Variables — Build-Time Injection vs Runtime Access$escape$,
  $escape$Turbopack handles environment variables differently from webpack. Variables prefixed with NEXT_PUBLIC_ are inlined at build time — Turbopack statically replaces every reference with the literal string value during compilation, making them immutable post-build. There's no webpack DefinePlugin equivalent you configure manually; Turbopack's define behavior is built into the Next.js layer via next.config.ts using the env key for custom build-time constants.

For runtime variables (no NEXT_PUBLIC_ prefix), Turbopack never bundles them into client code — they remain server-side only, accessible via process.env on the Node.js runtime. Attempting to read a non-prefixed variable in a Client Component returns undefined silently.

To inject arbitrary build-time constants (like feature flags or API versions), use next.config.ts env field. Turbopack reads this during its module graph traversal and performs dead-code elimination on branches that resolve to false constants — a meaningful tree-shaking win over runtime checks. Always validate required env vars at startup using a Zod schema rather than scattering process.env reads across modules.$escape$,
  $escape$// next.config.ts
import type { NextConfig } from 'next';

const config: NextConfig = {
  env: {
    API_VERSION: 'v2',
    FEATURE_NEW_FEED: process.env.FEATURE_NEW_FEED ?? 'false',
  },
};

export default config;

// app/components/Feed.tsx (Client Component)
// Turbopack inlines API_VERSION at build time — no runtime lookup
const endpoint = `/api/${process.env.API_VERSION}/feed`;

// Dead-code eliminated by Turbopack if FEATURE_NEW_FEED === 'false'
if (process.env.FEATURE_NEW_FEED === 'true') {
  renderNewFeed();
}$escape$,
  $escape$typescript$escape$,
