INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '93dfaaf5-51d7-4153-ba39-e570ff5729b9',
  '00000000-0000-0000-0000-000000000001',
  $escape$Turbopack CSS Processing — PostCSS, CSS Modules, and Preprocessor Support Out of the Box$escape$,
  $escape$Turbopack handles CSS processing through its built-in transform pipeline, which integrates PostCSS automatically when a `postcss.config.js` (or `.cjs`) is present at the project root — no additional configuration needed. CSS Modules are natively supported: any file ending in `.module.css` is scoped automatically, with hashed class names generated at build time rather than runtime, giving you faster HMR updates compared to webpack's approach.

For preprocessors, Turbopack supports Sass/SCSS via `sass` package installation — just `npm install sass` and import `.scss` files directly. Less is not currently supported. Notably, Turbopack processes CSS Modules before PostCSS, meaning your `postcss.config.js` plugins (e.g. `autoprefixer`, `tailwindcss`) run on already-scoped output.

One critical difference from webpack: Turbopack does not support `@import` of non-CSS files inside `.css` files using loaders. Keep preprocessor imports within `.scss`/`.sass` files exclusively. Global styles imported in `_app.tsx` or `layout.tsx` are processed through the same pipeline without any special casing.$escape$,
  $escape$// postcss.config.js — auto-detected by Turbopack at project root
module.exports = {
  plugins: {
    tailwindcss: {},
    autoprefixer: {},
  },
};

// Component using CSS Modules (scoped, HMR-optimized in Turbopack)
import styles from './Button.module.css';

export function Button({ label }: { label: string }) {
  return <button className={styles.primary}>{label}</button>;
}

// Button.module.scss — Sass works after: npm install sass
.primary {
  @apply bg-blue-600 text-white px-4 py-2 rounded;
  &:hover { @apply bg-blue-700; }
}$escape$,
