INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '9ef99ac7-5e88-4e1e-9193-51757bb4b68a',
  '00000000-0000-0000-0000-000000000001',
  $escape$Turbopack Path Resolution — tsconfig Aliases vs. resolveAlias$escape$,
  $escape$Turbopack reads `tsconfig.json` `compilerOptions.paths` natively — no `babel-plugin-module-resolver` or `webpack.resolve.alias` shim needed. Set `baseUrl: "."` alongside your `paths` map and Turbopack picks them up automatically when running `next dev --turbopack`.

For bundler-level remapping — swapping an entire third-party package, e.g. pointing `lodash` to `lodash-es` — use `resolveAlias` inside the `turbopack` key in `next.config.ts`. This key graduated out of `experimental.turbo` in Next.js 15. It operates on the module graph before TypeScript awareness, so it covers JS-only imports that `tsconfig paths` cannot touch.

One critical gotcha: Turbopack resolves `paths` patterns literally at runtime. Aliasing `"@/utils": ["./src/utils"]` will not match an import of `@/utils/format` — you need the wildcard form `"@/utils/*": ["./src/utils/*"]`. TypeScript's language server may autocomplete the import correctly while Turbopack still fails to resolve it, so keep path patterns consistent.

`resolveExtensions` in the same block controls the extension probe order, defaulting to `[".tsx", ".ts", ".jsx", ".js", ".mjs", ".cjs"]`.$escape$,
  $escape$// next.config.ts
import type { NextConfig } from 'next';

const nextConfig: NextConfig = {
  turbopack: {
    resolveAlias: {
      'lodash': 'lodash-es',          // swap entire package at graph level
      '@ui': './src/components/ui',   // static alias (no wildcard)
    },
    resolveExtensions: ['.tsx', '.ts', '.jsx', '.js'],
  },
};

export default nextConfig;$escape$,
  $escape$typescript$escape$,
