INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '0d264fa8-5cff-44c2-8e97-fe1a64b98974',
  '00000000-0000-0000-0000-000000000001',
  $escape$Turbopack's Persistent Caching — Why Your Second Build Is Near-Instant$escape$,
  $escape$Turbopack stores build artifacts in a persistent on-disk cache under `.next/cache/turbopack`. Unlike webpack's cache which serializes entire module graphs, Turbopack caches at the granularity of individual task outputs — each transform, resolve, and chunk emission is a discrete node in a demand-driven task graph. When you change a single file, only the subgraph downstream of that file is invalidated and re-executed; everything else is a cache hit.

This is powered by Turbopack's `turbo-tasks` runtime, which tracks fine-grained input/output dependencies automatically. You don't annotate anything — the framework observes which cached values each task reads and rewrites only what changed.

To force a full cache bust during debugging, delete `.next/cache/turbopack` or pass `--no-cache` to your dev command. For CI pipelines, restore this directory between runs using your runner's cache action — Turbopack's cache is fully relocatable and keyed by content hash, not absolute path. Teams on large Next.js 15 monorepos report cold CI builds dropping from 4+ minutes to under 40 seconds after wiring this up.$escape$,
  $escape$# next.config.ts — enable Turbopack (stable in Next.js 15)
import type { NextConfig } from 'next';

const nextConfig: NextConfig = {
  experimental: {
    turbo: {
      // Extend module resolution rules (replaces webpack loaders)
      rules: {
        '*.svg': {
          loaders: ['@svgr/webpack'],
          as: '*.js',
        },
      },
    },
  },
};

export default nextConfig;$escape$,
  $escape$typescript$escape$,
