INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'dd176192-39be-403a-895f-a72de4d008e4',
  '00000000-0000-0000-0000-000000000001',
  $escape$Turbopack Production Optimization — Minification, Compression, and Dead Code Elimination$escape$,
  $escape$Turbopack's production pipeline uses SWC's native Rust minifier instead of Terser — it's enabled automatically with `next build --turbopack` and requires zero config. Unlike webpack, Turbopack builds a fine-grained module graph entirely in Rust, enabling more precise dead code elimination: only exports statically reachable from your entry points survive. Dynamic `import()` boundaries define automatic split points, so lazy routes drop out of the critical bundle without any manual chunking hints.

For compression, Turbopack defers to Next.js's `compress: true` option (gzip via Node's zlib). Brotli isn't emitted natively — offload it to Azure Front Door, Cloudflare, or your CDN. The one silent tree-shaking killer: barrel files (`index.ts` re-exporting everything). Turbopack can't statically analyze non-explicit re-exports, so unused code leaks through. Use `optimizePackageImports` in `next.config.ts` to force granular resolution for heavy libraries. To audit what actually ships, run with `NEXT_TURBOPACK_TRACING=1` and inspect the generated `.next/trace` file via Turbopack's trace viewer.$escape$,
  $escape$// next.config.ts
import type { NextConfig } from 'next'

const nextConfig: NextConfig = {
  compress: true, // gzip via zlib; brotli belongs on your CDN
  experimental: {
    // Forces granular imports — defeats barrel-file tree-shaking leaks
    optimizePackageImports: ['lucide-react', 'date-fns', '@radix-ui/react-icons'],
  },
}

export default nextConfig

// Inspect the production trace:
// NEXT_TURBOPACK_TRACING=1 next build --turbopack$escape$,
  $escape$typescript$escape$,
