INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '0afa9b9d-edf5-46ad-97e9-d40231e8f2d5',
  '00000000-0000-0000-0000-000000000001',
  $escape$Turbopack Plugin System — Extending the Build Pipeline with Loader Rules$escape$,
  $escape$Turbopack doesn't expose a hook-based plugin API like webpack's Tapable. Instead, it extends the build pipeline through `turbopack.rules` in `next.config.ts` — a file-glob-to-loader mapping that runs webpack-compatible loaders as Turbopack transforms. Each rule targets a file pattern and chains one or more loaders, which Turbopack executes in a Rust-managed async task graph rather than Node.js worker threads — meaning loader output is cached at the task boundary, not per-compilation.

Loaders receive the same `this` context as in webpack (`resourcePath`, `query`, etc.), but hooks like `this.emitFile` and `this.addDependency` have partial support — verify against the Turbopack loader compatibility matrix before migrating. The `as` field normalizes output MIME type so Turbopack's internal module graph correctly classifies the transform result (e.g., treating `.svg` output as `.js`). `resolveAlias` complements rules by intercepting module resolution before the loader pipeline runs, making it the right lever for polyfilling or swapping Node built-ins at build time.$escape$,
  $escape$// next.config.ts
import type { NextConfig } from 'next';

const config: NextConfig = {
  turbopack: {
    rules: {
      '*.svg': {
        loaders: ['@svgr/webpack'],
        as: '*.js',
      },
      '*.mdx': {
        loaders: ['@mdx-js/loader'],
        as: '*.js',
      },
    },
    resolveAlias: {
      'node-fetch': 'cross-fetch',
    },
  },
};

export default config;$escape$,
  $escape$typescript$escape$,
