INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '247b8128-043c-468f-a433-604178b46ee0',
  '00000000-0000-0000-0000-000000000001',
  $escape$Turbopack vs. Vite's Three-Tool Split: Why There's No optimizeDeps$escape$,
  $escape$Turbopack is a direct architectural rejection of Vite's three-tool pipeline: native ESM serving in dev, esbuild for dependency pre-bundling, and Rollup for production. Vite's unbundled ESM dev server is elegant but degrades badly at scale — thousands of individual module requests create a waterfall that bogs down cold starts on large apps. That's why Vite introduced `optimizeDeps.include`: a manual escape hatch to pre-bundle problematic CJS dependencies with esbuild.

Turbopack sidesteps this entirely with demand-driven bundling. When the browser requests a route, Turbopack traces only that route's dependency graph and bundles exactly what's needed — no pre-bundling phase, no `optimizeDeps` hacks. The Turbo engine's incremental cache stores computation results keyed by file content and transform inputs, so subsequent requests for overlapping modules hit the cache at a function-call level of granularity.

Critically, Turbopack uses a single SWC-based transform pipeline in both dev and production. Vite's esbuild-in-dev, Rollup-in-prod split is a known source of behavioral divergence — plugins that work in dev silently break in prod. Turbopack eliminates that entire class of bug by never splitting the pipeline.$escape$,
  $escape$// next.config.ts (Next.js 15+)
import type { NextConfig } from 'next'

const config: NextConfig = {
  turbopack: {
    // No optimizeDeps equivalent — Turbopack doesn't pre-bundle
    resolveAlias: {
      // Redirect CJS packages without a pre-bundling step
      'lodash': 'lodash-es',
    },
    rules: {
      '*.svg': {
        loaders: ['@svgr/webpack'],
        as: '*.js',
      },
    },
  },
}

export default config$escape$,
  $escape$typescript$escape$,
