INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '9ee89ed9-618d-4e77-b8bc-ee5f962f5a7c',
  '00000000-0000-0000-0000-000000000001',
  $escape$Turbopack — No Plugins, Selective Loaders, and Module Federation's New Shape$escape$,
  $escape$Turbopack collapses webpack's loader/plugin split by design. Plugins don't exist — what webpack plugins did (tree-shaking, chunk splitting, asset hashing) is baked into Turbopack's Rust core and configured via next.config.ts top-level keys, not a plugin array. Loaders survive, but only for file-level transforms. You wire them through `turbopack.rules`, mapping glob patterns to webpack-compatible loaders with an explicit `as` target so Turbopack knows the output module type. Not all loaders are supported — those that tap webpack's compilation lifecycle (html-webpack-plugin, mini-css-extract-plugin) have no equivalent surface.

Module Federation gets its own story. Turbopack ships native MF support — no `ModuleFederationPlugin` import. You declare remotes and exposes inside the `turbopack.modulefederation` key. Turbopack handles the async boundary and shared singleton negotiation at the Rust layer, so the runtime overhead is lower than webpack's JS-based container runtime. The gotcha: `eager` shared modules behave differently — Turbopack enforces async chunks at federation boundaries even when `eager: true` is set, so bootstrapping via a dynamic import wrapper is still required.$escape$,
  $escape$// next.config.ts
import type { NextConfig } from 'next'

const config: NextConfig = {
  turbopack: {
    rules: {
      '*.svg': {
        loaders: ['@svgr/webpack'],
        as: '*.js',
      },
    },
    moduleFederation: {
      name: 'shell',
      remotes: {
        ui: 'ui@http://localhost:3001/_next/static/chunks/remoteEntry.js',
      },
      shared: { react: { singleton: true, requiredVersion: '^19.0.0' } },
    },
  },
}

export default config$escape$,
  $escape$typescript$escape$,
