INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '5bef76d9-d396-40ec-ad3c-2d9071e60a56',
  '00000000-0000-0000-0000-000000000001',
  $escape$Turbopack in a Monorepo — Native Workspace Resolution Without Transpile Hacks$escape$,
  $escape$Turbopack resolves workspace packages by tracing the module graph directly from source — no pre-build step required. Unlike webpack-based setups, you don't need `transpilePackages` for every internal package; Turbopack natively understands package `exports` fields and TypeScript path aliases configured in `tsconfig.json`.

For shared configs (ESLint, tsconfig, Tailwind), reference them via `extends` from a workspace package — Turbopack picks up the inheritance during its incremental compilation pass without needing to watch config files explicitly.

Turborepo integration tightens the loop: in `turbo.json`, mark your `dev` task as `persistent: true` and add `dependsOn: ["^build"]` so shared packages compile before the consuming app starts. Turbopack's file-system watcher operates at the workspace root, meaning a change in `packages/ui` triggers hot module replacement in `apps/web` without manual cache busting.

One gotcha: workspace packages using non-standard or conditional `exports` maps won't resolve automatically. Patch them with `resolveAlias` under the `turbopack` key in `next.config.ts`. Reserve `transpilePackages` only for CJS-only packages that ship without an `exports` field.$escape$,
  $escape$// next.config.ts
import type { NextConfig } from 'next';

const config: NextConfig = {
  turbopack: {
    resolveAlias: {
      '@repo/ui': '../../packages/ui/src/index.ts',
    },
    resolveExtensions: ['.tsx', '.ts', '.jsx', '.js'],
  },
  // Only needed for CJS-only packages without an `exports` field
  transpilePackages: ['@repo/legacy-utils'],
};

export default config;$escape$,
  $escape$typescript$escape$,
