INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '1b9b5148-9597-410c-90a3-5f3d0a491b1a',
  '00000000-0000-0000-0000-000000000001',
  $escape$Turbopack — Sharing Configs Across a Monorepo and Caching CI Builds$escape$,
  $escape$Turbopack's configuration lives under the `turbopack` key in `next.config.ts`, introduced in Next.js 15. In a monorepo, share a base config by exporting a typed `NextConfig['turbopack']` object from a shared package and spreading it per-app — this keeps loader rules and `resolveAlias` maps DRY across workspaces. To extend, spread the base and override specific keys; `resolveAlias` and `rules` are both plain objects, so a shallow spread is enough for most cases.

For CI, Turbopack's incremental cache lives at `.next/cache/turbopack`. Cache this directory in GitHub Actions using `actions/cache` keyed on a hash of `package-lock.json` and `next.config.ts`. On a cache hit, Turbopack skips recompiling unchanged modules — cold CI builds that took 90s can drop under 10s after the first run. With Turborepo remote caching enabled (`turbo login && turbo link`), `.next/cache/turbopack` artifacts are shared across all CI runners and developer machines via Vercel's content-addressed store, giving you distributed cache hits without any extra configuration.$escape$,
  $escape$// packages/turbopack-config/index.ts
import type { NextConfig } from 'next'

export const base: NextConfig['turbopack'] = {
  rules: {
    '*.svg': { loaders: ['@svgr/webpack'], as: '*.js' },
  },
  resolveAlias: { '@shared': '../../packages/ui/src' },
}

// apps/web/next.config.ts
import { base } from '@repo/turbopack-config'
const config: NextConfig = {
  turbopack: { ...base, resolveAlias: { ...base.resolveAlias, '@app': './src' } },
}
export default config$escape$,
  $escape$typescript$escape$,
